import { useCanvas } from '../hooks/useCanvas.js';
import { LineCanvasInstance, LineCanvasProps } from '../types/canvas-shape.js';
import { printLineBuilder } from '../utils/shapes/line-canvas.js';

export function LineCanvas<Datum>(props: LineCanvasProps<Datum>) {
  const {
    radius,
    strokeWidth = 2,
    enableDotOverflow = false,
    overlayPadding,
    ...propsLineCanvas
  } = props;

  // Build how Line canvas should style
  const drawLine = printLineBuilder<Datum>(
    strokeWidth,
    enableDotOverflow,
    radius,
    overlayPadding,
  );

  const drawLineCanvas = (
    ctx: CanvasRenderingContext2D,
    canvas: LineCanvasInstance<Datum>,
  ) => {
    drawLine(ctx, canvas, canvas.x, canvas.y);
  };

  useCanvas('line', (ctx: CanvasRenderingContext2D) =>
    drawLineCanvas(ctx, propsLineCanvas),
  );

  return null;
}
